const item = $input.first().json;
const prompt = `Responda a pergunta usando apenas o contexto. Se o contexto for insuficiente, diga que precisa de mais documentos.

Pergunta: ${item.question}

Contexto recuperado:
${item.retrieved_context}`;
return [{ json: { ...item, prompt } }];

const response = $input.first().json;
const answer = response.choices?.[0]?.message?.content || JSON.stringify(response);
return [{ json: { answer, sources: ['simulated_context'], created_at: new Date().toISOString() } }];
